import React from "react";
import "./InternshipModal.css";

const InternshipModal = ({
  internship,
  onClose,
  onApply,
  onEdit,
  onDelete,
  userRole,
  hasApplied,
}) => {
  if (!internship) return null;

  return (
    <div className="modal-overlay">
      <div className="modal-content">
        <button className="modal-close" onClick={onClose}>✖</button>
        <h2>{internship.title}</h2>
        <p><strong>Company:</strong> {internship.company}</p>
        <p><strong>Location:</strong> {internship.location}</p>
        <p><strong>Stipend:</strong> {internship.stipend}</p>
        <p><strong>Duration:</strong> {internship.duration}</p>
        <p><strong>Description:</strong></p>
        <p>{internship.description}</p>
        <div className="modal-actions">
          {userRole === "student" && (
            <button
              onClick={() => onApply(internship._id)}
              disabled={hasApplied}
              className={hasApplied ? "applied" : ""}
            >
              {hasApplied ? "Applied ✅" : "Apply Now"}
            </button>
          )}
          {(userRole === "admin" || userRole === "hr") && (
            <>
              <button onClick={() => onEdit(internship)}>Edit</button>
              <button onClick={() => onDelete(internship._id)} className="danger">Delete</button>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default InternshipModal;
